LAYER
	NAME 'POL'
	TYPE POINT
	DUMP true
	TEMPLATE fooOnlyForWMSGetFeatureInfo 
	INCLUDE "datashare.inc"	
	DATA "sp_geometry FROM (
		SELECT m.*
		FROM vw_att_details_pole_map m
		WHERE (%NetworkFilter% > 0 AND EXISTS (
					SELECT 1
					FROM polygon_master pm
					WHERE ST_Within(m.sp_geometry, pm.sp_geometry)
					  AND pm.entity_type = 'Network_Ticket'
					  AND pm.system_id = %NetworkFilter%
				))
				OR (
					%NetworkFilter% = 0
					AND NOT EXISTS (
						SELECT 1
						FROM user_master
						WHERE user_id = %UserId%
						  AND lower(user_type) = 'vendor'
					)
				)
		) AS a USING UNIQUE system_id USING SRID=4326"
	FILTER (%provinceFilter% AND (%layerFilter% ) AND (%prjectspecificationFilter% ) AND (%ownershipFilter% ) AND (%AutoPlanningNetworkFilter%))
			
	VALIDATION		
		'provinceFilter'   '.*'
		'layerFilter'   '.*'
		'prjectspecificationFilter'   '.*'
		'ownershipFilter'   '.*'							
		'NetworkFilter'   '.*'
		'AutoPlanningNetworkFilter' '.*'
		'UserId' '.*'
	END 
	METADATA
		'ows_title' 'POLE'
	END
	STATUS OFF
	LABELITEM 'label_column'
	GROUP 'Network'		
									
	CLASS
		NAME 'Pole'
		EXPRESSION ('[specification]' ~* '7 M' AND '[network_status]'  eq 'P')
		STYLE
			SYMBOL "icons/Planned/Pole6.7.png"
			SIZE 30
			OFFSET 0 -5				
		END
		LEADER
		  GRIDSTEP 6
		  MAXDISTANCE 10000
		  STYLE
			COLOR 200 100 100
			WIDTH 1
		  END
		END
		LABEL 
			COLOR  255 0 0  		
			FONT "arial"
			TYPE truetype
			SIZE 8
			POSITION AUTO
			PARTIALS FALSE	
		END				
	END
	CLASS
		NAME 'Pole'
		EXPRESSION ('[specification]' ~* '7 M' AND '[network_status]'  eq 'A')  			
		STYLE
			SYMBOL "icons/AsBuild/Pole6.7.png"
			SIZE 20			
		END
		LEADER
		  GRIDSTEP 6
		  MAXDISTANCE 10000
		  STYLE
			COLOR 200 100 100
